"""Headless eval-only execution for managed runs.

Given precomputed component responses, this runs eval components in their real
runtime (live Python objects here; TypeScript via the Node runner) and emits
``EvaluationResult``-shaped JSON. It is the unit the Trigger.dev container
invokes: evals run as real modules with their real dependencies, never in a
dependency-stripped sandbox.

Input payload (JSON):
    {
      "items": [
        {
          "item_id": "...",
          "eval_target": "evals.py:report_completeness_eval",
          "language": "python" | "typescript",
          "context": {"model_input": "...", "model_response": "...", "expected_output": "..."}
        },
        ...
      ]
    }

Output (JSON): a list of EvaluationResult dicts:
    [{"item_id", "name", "score", "status", "error"?, "code_failed_rationale"?}, ...]
"""
from __future__ import annotations

import asyncio
import os
import secrets
from dataclasses import asdict, dataclass
from typing import Any

# The eval contract is text-only: the eval fn receives the model response as a
# string and is responsible for parsing it (matches local execution semantics).
_CONTEXT_KEYS = ("model_input", "model_response", "expected_output")


@dataclass
class EvalItemResult:
    item_id: str
    name: str
    score: float
    status: str  # "success" | "error"
    error: str | None = None
    code_failed_rationale: list[str] | None = None

    def to_dict(self) -> dict[str, Any]:
        data = asdict(self)
        if data["error"] is None:
            del data["error"]
        if data["code_failed_rationale"] is None:
            del data["code_failed_rationale"]
        return data


def _context_kwargs(context: dict[str, Any]) -> dict[str, str]:
    return {key: context.get(key, "") for key in _CONTEXT_KEYS}


def _extract_score(output: Any) -> float:
    if isinstance(output, (int, float)) and not isinstance(output, bool):
        return float(output)
    if isinstance(output, dict):
        try:
            return float(output.get("score", 0.0))
        except (TypeError, ValueError):
            return 0.0
    return 0.0


def _extract_rationale(output: dict[str, Any]) -> list[str]:
    rationale = output.get("rationale")
    if rationale is None:
        rationale = output.get("reason")
    if rationale is None:
        return []
    if isinstance(rationale, list):
        return [str(v) for v in rationale]
    return [str(rationale)]


async def run_typescript_eval_item(
    eval_target: str,
    context: dict[str, Any],
    item_id: str,
) -> "EvalItemResult":
    """Run a single TypeScript eval component via the SDK Node runner (eval-only mode)."""
    import json
    import shutil
    import subprocess

    npx = shutil.which("npx")
    if npx is None:
        return EvalItemResult(
            item_id=item_id, name="", score=0.0, status="error",
            error="npx not found; cannot execute TypeScript eval"
        )

    payload = json.dumps(_context_kwargs(context))
    try:
        proc = subprocess.run(
            [npx, "--no-install", "zhanla-sdk-ts", "eval-only", eval_target],
            input=payload + "\n",
            capture_output=True,
            text=True,
            timeout=120,
            env={**os.environ, "ZHANLA_INTERNAL": secrets.token_hex(32)},
        )
    except subprocess.TimeoutExpired:
        return EvalItemResult(
            item_id=item_id, name="", score=0.0, status="error",
            error="TypeScript eval timed out after 120s"
        )
    except Exception as exc:
        return EvalItemResult(
            item_id=item_id, name="", score=0.0, status="error", error=str(exc)
        )

    stdout = proc.stdout.strip()
    if not stdout:
        stderr = proc.stderr.strip()
        return EvalItemResult(
            item_id=item_id, name="", score=0.0, status="error",
            error=f"No output from TypeScript eval runner. stderr: {stderr}"
        )

    try:
        line = stdout.splitlines()[-1]
        result = json.loads(line)
    except Exception as exc:
        return EvalItemResult(
            item_id=item_id, name="", score=0.0, status="error",
            error=f"Failed to parse TypeScript eval output: {exc}. stdout: {stdout}"
        )

    if result.get("status") == "error":
        return EvalItemResult(
            item_id=item_id, name="", score=0.0, status="error",
            error=result.get("error", "Unknown TypeScript eval error")
        )

    eval_output = result.get("eval_output") or {}
    name = str(result.get("name", "") or "")
    score = _extract_score(eval_output)
    item_result = EvalItemResult(item_id=item_id, name=name, score=score, status="success")
    if score < 1 and isinstance(eval_output, dict):
        rationale = _extract_rationale(eval_output)
        if rationale:
            item_result.code_failed_rationale = rationale
    return item_result


async def run_python_eval_item(
    eval_component: Any,
    context: dict[str, Any],
    item_id: str,
) -> EvalItemResult:
    """Run a single Python eval component against a precomputed response context."""
    from zhanla_cli.executor import _execute_component

    name = getattr(eval_component, "name", "") or ""
    try:
        output = await _execute_component(eval_component, _context_kwargs(context))
    except Exception as exc:  # eval bodies are user code; surface failures as errors
        return EvalItemResult(
            item_id=item_id, name=name, score=0.0, status="error", error=str(exc)
        )

    score = _extract_score(output)
    result = EvalItemResult(item_id=item_id, name=name, score=score, status="success")
    if score < 1 and isinstance(output, dict):
        rationale = _extract_rationale(output)
        if rationale:
            result.code_failed_rationale = rationale
    return result


async def _run_item(item: dict[str, Any]) -> EvalItemResult:
    item_id = str(item.get("item_id", ""))
    language = item.get("language", "python")
    eval_target = item.get("eval_target", "")
    context = item.get("context", {}) or {}

    if language == "python":
        from zhanla_cli.discovery import discover_eval

        try:
            eval_component = discover_eval(eval_target)
        except Exception as exc:
            return EvalItemResult(
                item_id=item_id, name="", score=0.0, status="error", error=str(exc)
            )
        return await run_python_eval_item(eval_component, context, item_id)

    if language == "typescript":
        return await run_typescript_eval_item(eval_target, context, item_id)

    return EvalItemResult(
        item_id=item_id,
        name="",
        score=0.0,
        status="error",
        error=f"Unknown eval language: {language!r}",
    )


async def run_eval_items(payload: dict[str, Any]) -> list[dict[str, Any]]:
    """Run all eval items in the payload, returning EvaluationResult dicts."""
    items = payload.get("items", []) or []
    results = [await _run_item(item) for item in items]
    return [r.to_dict() for r in results]


def run_eval_items_sync(payload: dict[str, Any]) -> list[dict[str, Any]]:
    return asyncio.run(run_eval_items(payload))
